pub struct PartyNameUpdateMessage {
    pub party_id: i32,
    pub party_name: String,
}

impl DofusSerialize for PartyNameUpdateMessage {
    fn serialize(&self, writer: &mut BigEndianWriter) {
        writer.write_var_int(self.party_id);
        writer.write_utf(&self.party_name);
    }
}

impl DofusDeserialize for PartyNameUpdateMessage {
    fn deserialize(reader: &mut BigEndianReader) -> Result<Self> {
        Ok(Self {
            party_id: reader.read_var_int()?,
            party_name: reader.read_utf()?,
        })
    }
}

impl DofusMessage for PartyNameUpdateMessage {
    const MESSAGE_ID: u16 = 9548;
}

/// Protocol message — ID: 9690
#[derive(Debug, Clone, Default)]
pub struct DungeonPartyFinderRoomContentUpdateMessage {
    pub dungeon_id: i16,
    pub added_players: Vec<DungeonPartyFinderPlayer>,
    pub removed_players_ids: Vec<i64>,
}

impl DofusSerialize for DungeonPartyFinderRoomContentUpdateMessage {
    fn serialize(&self, writer: &mut BigEndianWriter) {
        writer.write_var_short(self.dungeon_id);
        writer.write_short(self.added_players.len() as _);
        for item in &self.added_players {
            item.serialize(writer);
        }
        writer.write_short(self.removed_players_ids.len() as _);
        for item in &self.removed_players_ids {
            writer.write_var_long(*item);
        }
    }
}

impl DofusDeserialize for DungeonPartyFinderRoomContentUpdateMessage {
    fn deserialize(reader: &mut BigEndianReader) -> Result<Self> {
        Ok(Self {
            dungeon_id: reader.read_var_short()?,
            added_players: {
                let count = reader.read_ushort()? as usize;
                let mut v = Vec::with_capacity(count);
                for _ in 0..count {
                    v.push(DungeonPartyFinderPlayer::deserialize(reader)?);
                }
                v
            },
            removed_players_ids: {
                let count = reader.read_ushort()? as usize;
                let mut v = Vec::with_capacity(count);
                for _ in 0..count {
                    v.push(reader.read_var_long()?);
                }
                v
            },
        })
    }
}

impl DofusMessage for DungeonPartyFinderRoomContentUpdateMessage {
    const MESSAGE_ID: u16 = 9690;
}

